{
  "name": "check_weather",
  "description": "Checks weather for a specific city",
  "type": "api_request",
  "active": true,
  "requires_confirmation": false,
  "execution_config": {
    "protocol": "https",
    "method": "GET",
    "url": "https://api.weather.com/v1/current/{city_id}",
    "headers": {
      "Authorization": "Bearer {{env.WEATHER_API_KEY}}",
      "Content-Type": "application/json"
    },
    "timeout": 5000
  },
  "parameters": {
    "city_id": {
      "type": "string",
      "required": true,
      "param_type": "path",
      "description": "The city ID"
    },
    "units": {
      "type": "string",
      "required": false,
      "default": "C",
      "param_type": "query",
      "description": "Temperature units",
      "enum": ["C", "F"]
    }
  },
  "response_config": {
    "mode": "json",
    "values": {
      "temperature": {
        "type": "string",
        "path": "data.temp"
      }
    },
    "template": "Current temperature: {{temperature}}",
    "on_error": "Failed to get weather"
  }
}

{
  "name": "book_flight",
  "description": "Books a flight using gRPC",
  "type": "rpc_request",
  "active": true,
  "requires_confirmation": true,
  "execution_config": {
    "protocol": "grpc",
    "host": "localhost:50051",
    "service": "BookingService",
    "method": "BookFlight",
    "proto_file": "./protos/booking.proto",
    "timeout": 10000
  },
  "parameters": {
    "destination": {
      "type": "string",
      "required": true,
      "param_type": "message_field",
      "description": "Destination airport code"
    },
    "date": {
      "type": "string",
      "required": true,
      "param_type": "message_field",
      "description": "Flight date YYYY-MM-DD"
    }
  },
  "response_config": {
    "mode": "json",
    "template": "Flight booked: {{ticket_id}}",
    "on_error": "Booking failed"
  }
}

{
  "description": "Updated: Checks weather for any city worldwide",
  "active": true,
  "requires_confirmation": true
}

{
  "name": "get_weather_info",
  "description": "Gets current weather conditions for any city worldwide",
  "active": true,
  "requires_confirmation": false,
  "execution_config": {
    "protocol": "https",
    "method": "GET",
    "url": "https://api.weather.com/v2/current/{city_id}",
    "headers": {
      "Authorization": "Bearer {{env.WEATHER_API_KEY}}",
      "Content-Type": "application/json"
    },
    "timeout": 8000
  },
  "parameters": {
    "city_id": {
      "type": "string",
      "required": true,
      "param_type": "path",
      "description": "City identifier"
    }
  },
  "response_config": {
    "mode": "json",
    "values": {
      "temp": {
        "type": "string",
        "path": "data.temperature"
      }
    },
    "template": "Temperature: {{temp}}°C",
    "on_error": "Weather service unavailable"
  }
}

